import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload, Globe, GraduationCap, User, Info } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminArtistForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('identity');

  const [formData, setFormData] = useState({
    Artist_ID: '',
    Full_Name: '',
    Full_Name_In_Arabic: '',
    Gender: '',
    Age: '',
    Nationality: '',
    Nationality_In_Arabic: '',
    Birth_Year: '',
    Birth_Country: '',
    Birth_City: '',
    Current_Country: '',
    Current_City: '',
    Undergraduate_Degree: '',
    Postgraduate_Degree: '',
    Artistic_Practices: '',
    Fields: '',
    Bio_In_English: '',
    Bio_In_Arabic: '',
    Cloudinary_Image1: '',
    Email: '',
    Website: '',
    Instagram: '',
    Status: 'Complete'
  });

  useEffect(() => {
    if (id) {
      AdminService.getArtistById(id).then((res: any) => setFormData(res.data));
    }
  }, [id]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertArtist(formData);
      toast.success("Archive Synchronized");
      navigate('/admin/artists');
    } catch (err) { toast.error("Update Failed"); }
    finally { setLoading(false); }
  };

  const Input = ({ label, field, placeholder = "" }: any) => (
    <div className="space-y-1">
      <label className="text-[9px] font-black uppercase text-gray-500 ml-1">{label}</label>
      <input 
        value={(formData as any)[field]} 
        onChange={e => setFormData({...formData, [field]: e.target.value})}
        className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-xs text-white outline-none focus:border-primary transition-all"
        placeholder={placeholder}
      />
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-6">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-500 font-bold text-[10px] uppercase tracking-widest hover:text-white">
          <ArrowLeft size={14} /> Back
        </button>
        <div className="flex gap-2">
          {['identity', 'origin', 'education', 'bio'].map(tab => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-primary text-black' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      <form onSubmit={handleSubmit} className="bg-[#0f0f0f] border border-white/5 rounded-[2.5rem] overflow-hidden shadow-2xl">
        <div className="p-10">
          {activeTab === 'identity' && (
            <div className="grid grid-cols-3 gap-6 animate-in fade-in slide-in-from-right-4">
              <Input label="Artist ID" field="Artist_ID" placeholder="AR01" />
              <Input label="Full Name (EN)" field="Full_Name" />
              <Input label="Full Name (AR)" field="Full_Name_In_Arabic" />
              <Input label="Gender" field="Gender" />
              <Input label="Age" field="Age" />
              <Input label="Nationality" field="Nationality" />
              <Input label="Instagram" field="Instagram" placeholder="@username" />
              <Input label="Email" field="Email" />
              <Input label="Website" field="Website" />
            </div>
          )}

          {activeTab === 'origin' && (
            <div className="grid grid-cols-2 gap-6 animate-in fade-in slide-in-from-right-4">
              <Input label="Birth Year" field="Birth_Year" />
              <Input label="Birth Country" field="Birth_Country" />
              <Input label="Birth City" field="Birth_City" />
              <Input label="Current Country" field="Current_Country" />
              <Input label="Current City" field="Current_City" />
              <Input label="Status" field="Status" />
            </div>
          )}

          {activeTab === 'education' && (
            <div className="grid grid-cols-1 gap-6 animate-in fade-in slide-in-from-right-4">
              <Input label="Undergraduate Degree" field="Undergraduate_Degree" />
              <Input label="Postgraduate Degree" field="Postgraduate_Degree" />
              <Input label="Fields of Interest" field="Fields" />
              <Input label="Artistic Practices" field="Artistic_Practices" />
            </div>
          )}

          {activeTab === 'bio' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
              <Input label="Cloudinary Image URL" field="Cloudinary_Image1" />
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-gray-500">Bio (EN)</label>
                  <textarea value={formData.Bio_In_English} onChange={e => setFormData({...formData, Bio_In_English: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-xs h-40 outline-none focus:border-primary" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-gray-500">Bio (AR)</label>
                  <textarea value={formData.Bio_In_Arabic} onChange={e => setFormData({...formData, Bio_In_Arabic: e.target.value})} className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-xs h-40 outline-none focus:border-primary text-right" dir="rtl" />
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="bg-white/5 p-6 border-t border-white/5 flex justify-end">
          <button type="submit" disabled={loading} className="bg-primary text-black px-10 py-4 rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] flex items-center gap-3 hover:scale-105 transition-all">
            <Save size={18} /> {loading ? "Saving..." : "Commit Record"}
          </button>
        </div>
      </form>
    </div>
  );
};
